parameters.jsCode:
const response = $input.first().json;
const script = response.choices[0].message.content;

// Limpiar script
const cleanScript = script
  .replace(/\[B-ROLL:[^\]]+\]/g, '')
  .replace(/\[PAUSA\]/g, '...')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

// Keywords para Pexels
const keywords = ['gym workout', 'fitness training', 'healthy food'];

// Titulo del video
const lines = script.split('\n').filter(l => l.trim().length > 5);
let title = '';
for (const line of lines) {
  const clean = line.replace(/^[#*\-_"\s]+/, '').replace(/[*_"]+$/, '').trim();
  if (clean.length > 10 && !clean.toLowerCase().includes('introduccion') && !clean.toLowerCase().includes('introducción')) {
    title = clean.substring(0, 100);
    break;
  }
}
if (!title) title = '3 errores que te impiden perder grasa';

// Descripcion para YouTube
const description = `${cleanScript.substring(0, 500)}...\n\n🔔 Suscríbete para más consejos de fitness\n\n#fitness #salud #perdergrasa #ejercicio #nutricion`;

// Preparar body para HeyGen
const heygenBody = JSON.stringify({
  video_inputs: [{
    character: {
      type: 'avatar',
      avatar_id: '229e4844d3cb4df2ad0d8a79d4e082f0',
      avatar_style: 'normal'
    },
    voice: {
      type: 'text',
      input_text: cleanScript.substring(0, 1500),
      voice_id: '64cde72345cb463c9719781063d87787'
    }
  }],
  dimension: { width: 1280, height: 720 },
  aspect_ratio: '16:9',
  test: false
});

return [{
  json: {
    fullScript: script,
    cleanScript: cleanScript.substring(0, 1500),
    title: title,
    description: description,
    brollKeyword: keywords[0],
    playlist: 'Consejos Directos',
    heygenBody: heygenBody
  }
}];

const heygenData = $('HeyGen - Estado Video').first().json;
const scriptData = $('Procesar Script').first().json;

const videoUrl = heygenData.data?.video_url || null;
const status = heygenData.data?.status || 'unknown';

return [{
  json: {
    videoUrl: videoUrl,
    status: status,
    title: scriptData.title,
    description: scriptData.description,
    playlist: scriptData.playlist,
    videoReady: status === 'completed' && videoUrl !== null
  }
}];
